/// Generate a unique GTS type code with the given suffix.
fn type_code(suffix: &str) -> String {
    format!(
        "gts.cf.core.rg.type.v1~x.test.{}{}.v1~",
        suffix,
        Uuid::now_v7().as_simple()
    )
}

/// Generate a unique non-RG domain type code for membership resources.
fn external_type_code(suffix: &str) -> String {
    format!(
        "gts.cf.core.idp.user.v1~x.test.{}{}.v1~",
        suffix,
        Uuid::now_v7().as_simple()
    )
}

/// System-level scope for direct DB assertions (no tenant filtering).
fn system_scope() -> AccessScope {
    AccessScope::allow_all()
}

async fn seed_type_row(db: &modkit_db::DBProvider<modkit_db::DbError>, code: &str) {
    let conn = db.conn().expect("get conn");
    let model = gts_type::ActiveModel {
        schema_id: Set(code.to_owned()),
        metadata_schema: Set(Some(json!({"__can_be_root": true}))),
        ..Default::default()
    };

    secure_insert::<GtsTypeEntity>(model, &system_scope(), &conn)
        .await
        .expect("seed type row");
}

